#include <string>
#include <algorithm>

long long solve(std::string s) {
    int L = 0, C = 0, T = 0;
    for (char c : s) {
        if (c == 'L') L++;
        else if (c == 'C') C++;
        else if (c == 'T') T++;
    }
    long long original = (long long)L * C * T;
    long long maxIncrease = 0;
    if (C > 0 && T > 0) maxIncrease = std::max(maxIncrease, (long long)C * T);
    if (L > 0 && T > 0) maxIncrease = std::max(maxIncrease, (long long)L * T);
    if (L > 0 && C > 0) maxIncrease = std::max(maxIncrease, (long long)L * C);
    return std::max(original, original + maxIncrease);
}
